import sys
from collections import defaultdict

def can_sort(t, test_cases):
    results = []
    for case in test_cases:
        n, a = case
        sorted_a = sorted(a)
        if a == sorted_a:
            results.append("YES")
            continue
        freq = defaultdict(int)
        for num in a:
            freq[num] += 1
        if any(freq[num] > 1 for num in freq):
            results.append("YES")
            continue
        pos = {num: i for i, num in enumerate(sorted_a)}
        visited = [False] * n
        cycles = 0
        for i in range(n):
            if not visited[i]:
                j = i
                while not visited[j]:
                    visited[j] = True
                    j = pos[a[j]]
                cycles += 1
        if (n - cycles) % 2 == 0:
            results.append("YES")
        else:
            results.append("NO")
    return results

def main():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    t = int(data[idx])
    idx += 1
    test_cases = []
    for _ in range(t):
        n = int(data[idx])
        idx += 1
        a = list(map(int, data[idx:idx+n]))
        idx += n
        test_cases.append((n, a))
    results = can_sort(t, test_cases)
    for res in results:
        print(res)

if __name__ == "__main__":
    main()

